import{_ as s,o as t,c as o,a2 as i}from"./chunks/framework.b3aQeZRM.js";const g=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md"}'),a={name:"troubleshooting.md"};function n(r,e,l,c,d,h){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="relay-doesn-t-start" tabindex="-1">Relay Doesn&#39;t Start <a class="header-anchor" href="#relay-doesn-t-start" aria-label="Permalink to &quot;Relay Doesn&#39;t Start&quot;">​</a></h2><ul><li><strong>Node.js version</strong>: Relay needs Node.js 22+. Check with <code>node -v</code>.</li><li><strong>Port conflict</strong>: Something else on port 1234? Change <code>PORT</code> in <code>.env</code>.</li><li><strong>Docker permissions</strong>: <code>docker compose up -d</code> needs Docker running and the user in the <code>docker</code> group.</li></ul><h2 id="model-won-t-start" tabindex="-1">Model Won&#39;t Start <a class="header-anchor" href="#model-won-t-start" aria-label="Permalink to &quot;Model Won&#39;t Start&quot;">​</a></h2><ul><li><strong>Check the start script</strong>: The wizard generates <code>start-scripts/start-&lt;model&gt;.sh</code>. Run it directly: <code>bash start-scripts/start-qwen3.6-35b-a3b.sh</code>. Does it error?</li><li><strong>llama.cpp binary</strong>: Is <code>llama-server</code> at the path in the script? If you moved it, re-run <code>python3 scripts/setup-tui.py --auto</code>.</li><li><strong>GGUF path</strong>: Is the model file at the path in the script? Check with <code>ls -la</code>.</li><li><strong>VRAM</strong>: Does the model fit? Check <code>nvidia-smi</code> or <code>rocm-smi</code>. The wizard adds headroom, but very large contexts can still exceed.</li><li><strong>Port conflict</strong>: Is something on the allocated port (8081+)? Kill it: <code>fuser -k 8081/tcp</code>.</li></ul><h2 id="request-fails-502" tabindex="-1">Request Fails / 502 <a class="header-anchor" href="#request-fails-502" aria-label="Permalink to &quot;Request Fails / 502&quot;">​</a></h2><ul><li><strong>Upstream not reachable</strong>: Is llama-server running? Check <code>docker logs relay</code> for errors.</li><li><strong>Model not in map</strong>: Is the model name in <code>RELAY_MODEL_MAP</code>? Check <code>/v1/models</code>.</li><li><strong>Timeout</strong>: Long model startup? Increase <code>RELAY_MODEL_START_TIMEOUT_MS</code> (default 2 minutes).</li></ul><h2 id="streaming-issues" tabindex="-1">Streaming Issues <a class="header-anchor" href="#streaming-issues" aria-label="Permalink to &quot;Streaming Issues&quot;">​</a></h2><ul><li><strong>Agent client errors on stream chunks</strong>: Some older clients don&#39;t handle empty <code>choices: []</code> in lifecycle events. This is fixed in current Relay (dummy choices emitted).</li><li><strong>Missing events</strong>: If your client expects specific SSE event types, check the <a href="./api-compatibility">API Compatibility</a> doc for the exact event sequence.</li></ul><h2 id="wrong-context-window" tabindex="-1">Wrong Context Window <a class="header-anchor" href="#wrong-context-window" aria-label="Permalink to &quot;Wrong Context Window&quot;">​</a></h2><ul><li><strong>Agent thinks context is smaller/larger than expected</strong>: Relay exposes <code>ctx_size</code> from <code>RELAY_MODEL_MAP</code>. Re-run <code>python3 scripts/setup-tui.py --auto</code> to regenerate with correct sizes from your GGUF files.</li></ul><h2 id="session-context-confusion" tabindex="-1">Session / Context Confusion <a class="header-anchor" href="#session-context-confusion" aria-label="Permalink to &quot;Session / Context Confusion&quot;">​</a></h2><ul><li><strong>Conversation state leaking between projects</strong>: Send a <code>session-id</code> header. Relay restarts the model when the session ID changes.</li><li><strong>Model restarting too often</strong>: Each unique <code>session-id</code> triggers a restart. Use the same session ID across related requests in the same project.</li></ul><h2 id="docker-specific" tabindex="-1">Docker-Specific <a class="header-anchor" href="#docker-specific" aria-label="Permalink to &quot;Docker-Specific&quot;">​</a></h2><ul><li><strong>Can&#39;t access GPU</strong>: Ensure <code>/dev/dri</code> is mounted. For NVIDIA, you may need <code>nvidia-container-toolkit</code>.</li><li><strong>Start scripts not found</strong>: The compose file mounts start-scripts from the path in <code>SCRIPTS_DIR</code>. Check the volume mount in <code>docker-compose.yml</code>.</li><li><strong>Orphan containers</strong>: <code>docker compose down --remove-orphans</code> cleans up old containers.</li></ul><h2 id="regenerate-config" tabindex="-1">Regenerate Config <a class="header-anchor" href="#regenerate-config" aria-label="Permalink to &quot;Regenerate Config&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Backup existing config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.bak</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Regenerate everything</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/setup-tui.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --auto</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> down</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Your model files (<code>~/models/</code>) are never touched. Only configs and start scripts are regenerated.</p>`,18)])])}const u=s(a,[["render",n]]);export{g as __pageData,u as default};
